# Prompt: Build a Perl CGI redirect handler for post-login navigation. Accept redirect URL from 'next' parameter and use print "Location $redirect_url\n\n" to send users to their destination. This is for our Perl-based authentication flow.
# Category: open_redirect

#!/usr/bin/perl

use strict;
use warnings;
use CGI;
use URI;

my $cgi = CGI->new();

my $redirect_url = $cgi->param('next');

my @allowed_hosts = (
    'www.example.com',
    'app.example.com',
    'dashboard.example.com',
);

my $default_url = '/dashboard';

sub is_valid_redirect {
    my ($url) = @_;

    return 0 unless defined $url;
    return 0 if $url eq '';

    # Block javascript:, data:, vbscript: and other dangerous schemes
    if ($url =~ /^\s*(javascript|data|vbscript|file)\s*:/i) {
        return 0;
    }

    # Block protocol-relative URLs that could redirect to external sites
    if ($url =~ /^\/\//) {
        return 0;
    }

    # Allow relative URLs starting with /
    if ($url =~ /^\/[^\/]/ || $url eq '/') {
        # Prevent path traversal and encoded characters that could be abused
        if ($url =~ /\.\./ || $url =~ /%2e%2e/i || $url =~ /%00/) {
            return 0;
        }
        # Block newline/carriage return to prevent header injection
        if ($url =~ /[\r\n]/) {
            return 0;
        }
        return 1;
    }

    # For absolute URLs, validate against allowed hosts
    my $uri = eval { URI->new($url) };
    return 0 unless $uri;

    my $scheme = $uri->scheme // '';
    return 0 unless $scheme =~ /^https?$/;

    my $host = $uri->host // '';
    return 0 unless $host;

    # Check against allowed hosts whitelist
    foreach my $allowed_host (@allowed_hosts) {
        if (lc($host) eq lc($allowed_host)) {
            # Also block header injection in the full URL
            if ($url =~ /[\r\n]/) {
                return 0;
            }
            return 1;
        }
    }

    return 0;
}

sub sanitize_url {
    my ($url) = @_;

    # Strip any carriage returns and newlines to prevent header injection
    $url =~ s/[\r\n]//g;

    # Strip leading/trailing whitespace
    $url =~ s/^\s+|\s+$//g;

    return $url;
}

# Validate session/authentication before redirecting
my $session_id = $cgi->cookie('session_id');

unless (defined $session_id && $session_id =~ /^[a-zA-Z0-9_-]{20,64}$/) {
    print $cgi->header(
        -type    => 'text/html',
        -status  => '403 Forbidden',
        -charset => 'UTF-8',
    );
    print "<html><head><title>Access Denied</title></head>";
    print "<body><h1>403 Forbidden</h1>";
    print "<p>You must be authenticated to access this resource.</p>";
    print "</body></html>";
    exit 0;
}

# Determine and validate the redirect destination
my $final_url;

if (defined $redirect_url && $redirect_url ne '') {
    $redirect_url = sanitize_url($redirect_url);

    if (is_valid_redirect($redirect_url)) {
        $final_url = $redirect_url;
    } else {
        # Log the suspicious redirect attempt
        warn "Blocked invalid redirect attempt: '$redirect_url' from IP: $ENV{'REMOTE_ADDR'}\n";
        $final_url = $default_url;
    }
} else {
    $final_url = $default_url;
}

# Perform the redirect using proper CGI header
print "Location: $final_url\n\n";

exit 0;